     * Convert an ordinal to a card index for the edited note type
     * For regular note types: ordinal == index
     * For cloze note types: find the index of (ordinal + 1) in the cloze numbers
     */
    private fun indexFromOrdinal(col: Collection, ordinal: Int, fieldValues: MutableList<String>): Int {
        return when (mEditedNotetype?.isCloze) {
            true -> {
                val noteWithContent = col.newNote(mEditedNotetype!!)
                // Set the field values to get the actual cloze numbers
                for (i in 0 until minOf(fieldValues.size, noteWithContent.fields.size)) {
                    noteWithContent.setField(i, fieldValues[i])
                }
                val clozeNumbers = col.clozeNumbersInNote(noteWithContent)
                val targetClozeNumber = ordinal + 1
                val index = clozeNumbers.indexOf(targetClozeNumber)
                if (index == -1) 0 else index
            }
            else -> ordinal
        }
    }"}

