     * For regular note types: ordinal == index
     * For cloze note types: find the index of (ordinal + 1) in the cloze numbers
     */
    private fun indexFromOrdinal(col: Collection, ordinal: Int, fieldValues: MutableList<String>): Int {
        if (mEditedNotetype == null || ordinal < 0) {
            return 0
